Uber has list of pods and list of cities. 
Fit all the cities within least possible number of pods. 
Each pod should only contain adjoining cities.

Each pod for Uber have attributes
 -Max Number of trips per weeks

Each City
- tripsperweek
- latitude, longitude


Example 1:-
List of Pods with thresholds
P1 {100}
P2{50}
P3 {50}
P4 {40}

List of cities {trip per week, lat, long)
C1 {20,0,0}
C2 {25,9,10}
C3 {40,4,5}
C4 {50, 15,16}
C5 {60, 15,17}

Output
P1 serve cities C5
P2 -- C1,C2
P3 --- C4 
P4 --- C3

import java.util.*;

class City {
    String name;
    int tripsPerWeek;
    double latitude;
    double longitude;

    City(String name, int tripsPerWeek, double latitude, double longitude) {
        this.name = name;
        this.tripsPerWeek = tripsPerWeek;
        this.latitude = latitude;
        this.longitude = longitude;
    }
}

class Pod {
    String name;
    int maxTripsPerWeek;
    List<City> cities;

    Pod(String name, int maxTripsPerWeek) {
        this.name = name;
        this.maxTripsPerWeek = maxTripsPerWeek;
        this.cities = new ArrayList<City>();
    }

    boolean canAddCity(City city) {
        int totalTrips = city.tripsPerWeek;
        for (City c : cities) {
            totalTrips += c.tripsPerWeek;
        }
        return totalTrips <= maxTripsPerWeek;
    }

    void addCity(City city) {
        cities.add(city);
    }
}

public class PodDistribution {

    static double calculateDistance(City c1, City c2) {
        // Simplified distance calculation, replace with actual geospatial calculation if needed
        double latDistance = Math.pow(c1.latitude - c2.latitude, 2);
        double lonDistance = Math.pow(c1.longitude - c2.longitude, 2);
        return Math.sqrt(latDistance + lonDistance);
    }

    static void distributeCitiesToPods(List<City> cities, List<Pod> pods) {
        Collections.sort(cities, new Comparator<City>() {
            @Override
            public int compare(City c1, City c2) {
                return c2.tripsPerWeek - c1.tripsPerWeek; // sort in descending order of trips
            }
        });

        for (City city : cities) {
            Pod closestPod = null;
            double minDistance = Double.MAX_VALUE;

            for (Pod pod : pods) {
                if (pod.canAddCity(city)) {
                    double distance = 0;
                    for (City c : pod.cities) {
                        distance += calculateDistance(city, c);
                    }
                    if (pod.cities.isEmpty() || distance < minDistance) {
                        closestPod = pod;
                        minDistance = distance;
                    }
                }
            }

            if (closestPod != null) {
                closestPod.addCity(city);
            }
        }
    }

    public static void main(String[] args) {
        List<City> cities = new ArrayList<City>();
        cities.add(new City("C1", 20, 0, 0));
        cities.add(new City("C2", 25, 9, 10));
        cities.add(new City("C3", 40, 4, 5));
        cities.add(new City("C4", 50, 15, 16));
        cities.add(new City("C5", 60, 15, 17));

        List<Pod> pods = new ArrayList<Pod>();
        pods.add(new Pod("P1", 100));
        pods.add(new Pod("P2", 50));
        pods.add(new Pod("P3", 50));
        pods.add(new Pod("P4", 40));

        distributeCitiesToPods(cities, pods);

        for (Pod pod : pods) {
            System.out.print(pod.name + " --- ");
            for (City city : pod.cities) {
                System.out.print(city.name + " ");
            }
            System.out.println();
        }
    }
}
